import React from 'react';
import { useAuth } from '../contexts/AuthContext';
import Login from './Login';
import Register from './Register';

interface ProtectedRouteProps {
  children: React.ReactNode;
  message?: string;
}

const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ 
  children, 
  message = "Vous devez être connecté pour accéder à cette page" 
}) => {
  const { isAuthenticated } = useAuth();
  const [showLogin, setShowLogin] = React.useState(false);
  const [showRegister, setShowRegister] = React.useState(false);

  if (isAuthenticated) {
    return <>{children}</>;
  }

  const handleSwitchToRegister = () => {
    setShowLogin(false);
    setShowRegister(true);
  };

  const handleSwitchToLogin = () => {
    setShowRegister(false);
    setShowLogin(true);
  };

  const handleCloseAuth = () => {
    setShowLogin(false);
    setShowRegister(false);
  };

  return (
    <>
      <div className="flex items-center justify-center min-h-screen bg-gray-50">
        <div className="text-center p-8">
          <div className="mb-8">
            <div className="mx-auto w-24 h-24 bg-blue-100 rounded-full flex items-center justify-center mb-4">
              <svg className="w-12 h-12 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
              </svg>
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Authentification requise</h2>
            <p className="text-gray-600 mb-6">{message}</p>
          </div>

          <div className="space-y-3">
            <button
              onClick={() => setShowLogin(true)}
              className="w-full bg-blue-600 text-white py-3 px-6 rounded-lg hover:bg-blue-700 transition-colors font-medium"
            >
              Se connecter
            </button>
            <button
              onClick={() => setShowRegister(true)}
              className="w-full bg-white text-blue-600 py-3 px-6 rounded-lg border border-blue-600 hover:bg-blue-50 transition-colors font-medium"
            >
              Créer un compte
            </button>
          </div>
        </div>
      </div>

      {showLogin && (
        <Login 
          onClose={handleCloseAuth} 
          onSwitchToRegister={handleSwitchToRegister} 
        />
      )}

      {showRegister && (
        <Register 
          onClose={handleCloseAuth} 
          onSwitchToLogin={handleSwitchToLogin} 
        />
      )}
    </>
  );
};

export default ProtectedRoute;
